#!/usr/bin/env bash
# vendor/book-engine/adapters/kapidox.sh — kapidox API documentation adapter
#
# Generates KDE-style API reference documentation using kapidox (kgenapidox).
# kapidox wraps Doxygen with KDE's standard HTML theme — the same output
# format used on api.kde.org.
#
# Upstream mirror: Interested-Deving-1896/kde-kapidox
# (tracks KDE's kapidox releases; install from mirror for version consistency)
#
# Usage:
#   BOOK_ENGINE=kapidox bash vendor/book-engine/scripts/export.sh
#
# Required env vars (set by export.sh):
#   BOOK_SRC    — source directory containing Doxyfile (default: DOCS)
#   BOOK_OUT    — output root directory (default: book)
#   BOOK_TITLE  — documentation title
#
# Optional env vars:
#   KAPIDOX_DOXYFILE  — path to Doxyfile (default: ${BOOK_SRC}/Doxyfile)
#   KAPIDOX_LOGO      — path to logo image for the generated docs
#   KAPIDOX_INSTALL_FROM_MIRROR — if true, install from kde-kapidox mirror
#                                  instead of PyPI (default: false)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "${SCRIPT_DIR}/../../.." && pwd)"

BOOK_SRC="${BOOK_SRC:-DOCS}"
BOOK_OUT="${BOOK_OUT:-book}"
BOOK_TITLE="${BOOK_TITLE:-API Reference}"
DRY_RUN="${DRY_RUN:-false}"
KAPIDOX_DOXYFILE="${KAPIDOX_DOXYFILE:-${BOOK_SRC}/Doxyfile}"
KAPIDOX_LOGO="${KAPIDOX_LOGO:-assets/brand/logo-option-1.png}"
KAPIDOX_INSTALL_FROM_MIRROR="${KAPIDOX_INSTALL_FROM_MIRROR:-false}"
KAPIDOX_MIRROR="Interested-Deving-1896/kde-kapidox"

info() { echo "[kapidox] $*" >&2; }
warn() { echo "[kapidox:warn] $*" >&2; }
dry()  { echo "[kapidox:dry-run] $*" >&2; }

OUTPUT_DIR="${REPO_ROOT}/${BOOK_OUT}/kapidox"

# ── Install kapidox ───────────────────────────────────────────────────────────
install_kapidox() {
    if command -v kgenapidox >/dev/null 2>&1; then
        info "kgenapidox already available: $(kgenapidox --version 2>/dev/null || echo 'version unknown')"
        return 0
    fi

    info "Installing kapidox..."

    # Ensure doxygen is available
    if ! command -v doxygen >/dev/null 2>&1; then
        apt-get install -y doxygen --quiet 2>/dev/null \
            || brew install doxygen 2>/dev/null \
            || { warn "doxygen not available — kapidox build will fail"; }
    fi

    if [[ "${KAPIDOX_INSTALL_FROM_MIRROR}" == "true" ]]; then
        info "Installing from mirror: ${KAPIDOX_MIRROR}"
        pip install "git+https://github.com/${KAPIDOX_MIRROR}.git" --quiet 2>/dev/null \
            || { warn "Mirror install failed — falling back to PyPI"; pip install kapidox --quiet 2>/dev/null || true; }
    else
        pip install kapidox --quiet 2>/dev/null \
            || { warn "PyPI install failed — trying mirror"; \
                 pip install "git+https://github.com/${KAPIDOX_MIRROR}.git" --quiet 2>/dev/null || true; }
    fi

    if ! command -v kgenapidox >/dev/null 2>&1; then
        warn "kgenapidox not found after install — skipping kapidox build"
        return 1
    fi
    info "kapidox installed: $(kgenapidox --version 2>/dev/null || echo 'ok')"
}

# ── Generate Doxyfile if missing ──────────────────────────────────────────────
ensure_doxyfile() {
    if [[ -f "${REPO_ROOT}/${KAPIDOX_DOXYFILE}" ]]; then
        info "Using existing Doxyfile: ${KAPIDOX_DOXYFILE}"
        return 0
    fi

    info "No Doxyfile found — generating minimal stub at ${KAPIDOX_DOXYFILE}"
    mkdir -p "$(dirname "${REPO_ROOT}/${KAPIDOX_DOXYFILE}")"
    cat > "${REPO_ROOT}/${KAPIDOX_DOXYFILE}" << 'DOXYEOF'
# Minimal Doxyfile for kapidox
# Generated by vendor/book-engine/adapters/kapidox.sh
# Customise as needed — see https://www.doxygen.nl/manual/config.html

PROJECT_NAME     = "fork-sync-all"
PROJECT_BRIEF    = "Org-wide mirror, sync, and template propagation control plane"
INPUT            = scripts/ vendor/unified-agnostic-api/
RECURSIVE        = YES
FILE_PATTERNS    = *.sh *.py *.md
EXTRACT_ALL      = YES
GENERATE_HTML    = YES
HTML_OUTPUT      = html
GENERATE_LATEX   = NO
QUIET            = YES
WARN_IF_UNDOCUMENTED = NO
DOXYEOF
    info "Doxyfile stub written — edit ${KAPIDOX_DOXYFILE} to customise input sources"
}

# ── Build ─────────────────────────────────────────────────────────────────────
if [[ "${DRY_RUN}" == "true" ]]; then
    dry "Would run: kgenapidox --title '${BOOK_TITLE}' --output-dir ${OUTPUT_DIR} ${BOOK_SRC}"
    dry "Doxyfile: ${KAPIDOX_DOXYFILE}"
    dry "Mirror: ${KAPIDOX_MIRROR}"
    exit 0
fi

install_kapidox || exit 0  # non-fatal — skip if unavailable
ensure_doxyfile

mkdir -p "${OUTPUT_DIR}"

info "Building API docs: title='${BOOK_TITLE}' src=${BOOK_SRC} out=${OUTPUT_DIR}"

# kgenapidox expects to run from the repo root
cd "${REPO_ROOT}"

KAPIDOX_ARGS=(
    "--title" "${BOOK_TITLE}"
    "--output-dir" "${OUTPUT_DIR}"
)

# Inject logo if available
if [[ -f "${REPO_ROOT}/${KAPIDOX_LOGO}" ]]; then
    KAPIDOX_ARGS+=("--logo" "${REPO_ROOT}/${KAPIDOX_LOGO}")
fi

kgenapidox "${KAPIDOX_ARGS[@]}" "${BOOK_SRC}" 2>/dev/null \
    || { warn "kgenapidox failed — check Doxyfile and input sources"; exit 1; }

info "kapidox build complete: ${OUTPUT_DIR}"
